#include <bits/stdc++.h>
using namespace std;
#define a first
#define b second
#define int long long
const int maxn=1e3+5;
pair<int,int> pii[maxn];
int t,m,tt,f[maxn][maxn],ans;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t>>m;
	for(int i=1;i<=m;i++){
		cin>>pii[i].a>>pii[i].b;
	}
	for(int i=1;i<=m;i++,tt^=1){
		for(int j=0;j<=t;j++){
			f[tt^1][j]=f[tt][j];
			if(j-pii[i].a>=0)f[tt^1][j]=max(f[tt^1][j],f[tt][j-pii[i].a]+pii[i].b);
		}
	}
	cout<<f[tt][t];
	return 0;
}
